[Form]
public class DBMSQLQueryStoreQuery extends FormRun
{

    QueryBuildRange qbrQueryStart;
    QueryBuildRange qbrQueryEnd;
    QueryBuildRange qbrPlanStart;
    QueryBuildRange qbrPlanEnd;

}

public DBMSQLQueryStoreQueryTextId getQueryTextId()
{
    return  DBMSQLQueryStoreExt.queryTextId;
}

public DBMSQLQueryStorePlanId getQueryPlanId()
{
    return DBMSQLQueryStorePlanExt.PlanId;
}

private void refreshPlanView()
{
    DBMSQLQueryStorePlanExt localPlan;
    select firstonly localPlan
    where localPlan.PlanId == DBMSQLQueryStorePlanExt.PlanId;
    DBMSQLQueryStorePlanExt.data(localPlan);
    DBMSQLQueryStorePlanExt_ds.setCurrent();
    DBMSQLQueryStorePlanExt_ds.refresh();
    element.enablePlanButtons();
}

private void enablePlanButtons()
{
    unforcePlan.enabled(DBMSQLQueryStorePlanExt.IsForcedPlan);
}

private void enableQueryButtons()
{
    disableAPRC.enabled(DBMSQLQueryStoreExt.isEnabledForAPRC);
}

private void refreshQueryView()
{
    DBMSQLQueryStoreExt localQuery;
    select firstonly localQuery
    where localQuery.queryId == DBMSQLQueryStoreExt.QueryId;
    DBMSQLQueryStoreExt.data(localQuery);
    DBMSQLQueryStoreExt_ds.setCurrent();
    DBMSQLQueryStoreExt_ds.refresh();
    element.enableQueryButtons();
}

public void executeQuery()
{
    Query query = this.query();

    // Reset limits first
    query.firstOnly10(false);
    query.firstOnly100(false);
    query.firstOnly1000(false);

    switch (TopSelectionComboBox.selection())
    {
        case DBMSQLQueryStatsTopEnum::Top10:
            query.firstOnly10(true);
            break;
        case DBMSQLQueryStatsTopEnum::Top100:
            query.firstOnly100(true);
            break;
        case DBMSQLQueryStatsTopEnum::Top1000:
            query.firstOnly1000(true);
            break;
    }
    if (filterFrom.dateTimeValue() || filterTo.dateTimeValue())
    {
        utcdatetime fromDateTime = filterFrom.dateTimeValue();
        utcdatetime toDateTime = filterTo.dateTimeValue();
        query.dataSourceTable(tableNum(DBMSQLQueryStorePlan)).enabled(true);
        query.dataSourceTable(tableNum(DBMSQLQueryStoreRuntimeStats)).enabled(true);
        query.dataSourceTable(tableNum(DBMSQLQueryStoreRuntimeStatsInterval)).enabled(true);
        switch(true)
        {
            case FromDateTime && toDateTime:
                qbrQueryStart.value(SysQuery::range(FromDateTime, ToDateTime));
                qbrQueryEnd.value(SysQuery::range(FromDateTime, ToDateTime));
                break;
            case FromDateTime && !ToDateTime:
                qbrQueryStart.value(SysQuery::range(FromDateTime, DateTimeUtil::maxValue()));
                qbrQueryEnd.value(SysQuery::range(FromDateTime, DateTimeUtil::maxValue()));
                break;
            case !FromDateTime && ToDateTime:
                qbrQueryStart.value(SysQuery::range(DateTimeUtil::minValue(), ToDateTime));
                qbrQueryEnd.value(SysQuery::range(DateTimeUtil::minValue(), ToDateTime));
                break;
        }
    }
    else
    {
        query.dataSourceTable(tableNum(DBMSQLQueryStorePlan)).enabled(false);
        query.dataSourceTable(tableNum(DBMSQLQueryStoreRuntimeStats)).enabled(false);
        query.dataSourceTable(tableNum(DBMSQLQueryStoreRuntimeStatsInterval)).enabled(false);
    }

    super();
}

/// <summary>
///
/// </summary>
public void init()
{
    super();
    QueryBuildDataSource qbds = this.queryBuildDataSource();
    qbds.addSortField(fieldNum(DBMSQLQueryStoreExt, totalDuration), SortOrder::Descending);
    QueryBuildDataSource qbdsPlan = qbds.addDataSource(tableNum(DBMSQLQueryStorePlan));
    qbdsPlan.joinMode(JoinMode::ExistsJoin);
    qbdsPlan.fetchMode(QueryFetchMode::One2One);
    qbdsPlan.addLink(fieldNum(DBMSQLQueryStoreExt, queryId), fieldNum(DBMSQLQueryStorePlan, queryId));
    QueryBuildDataSource qbdsRuntimeStats = qbdsPlan.addDataSource(tableNum(DBMSQLQueryStoreRuntimeStats));
    qbdsRuntimeStats.joinMode(JoinMode::InnerJoin);
    qbdsRuntimeStats.fetchMode(QueryFetchMode::One2One);
    qbdsRuntimeStats.addLink(fieldNum(DBMSQLQueryStorePlan, planId), fieldNum(DBMSQLQueryStoreRuntimeStats, planId));
    QueryBuildDataSource qbdsRuntimeStatsInterval = qbdsRuntimeStats.addDataSource(tableNum(DBMSQLQueryStoreRuntimeStatsInterval));
    qbdsRuntimeStatsInterval.joinMode(JoinMode::InnerJoin);
    qbdsRuntimeStatsInterval.fetchMode(QueryFetchMode::One2One);
    qbdsRuntimeStatsInterval.addLink(fieldNum(DBMSQLQueryStoreRuntimeStats, RuntimeStatsIntervalId), fieldNum(DBMSQLQueryStoreRuntimeStatsInterval, RuntimeStatsIntervalId));
    qbrQueryStart =  qbdsRuntimeStatsInterval.addRange(fieldNum(DBMSQLQueryStoreRuntimeStatsInterval, startTime));
    qbrQueryEnd =  qbdsRuntimeStatsInterval.addRange(fieldNum(DBMSQLQueryStoreRuntimeStatsInterval, endTime));
}

/// <summary>
///
/// </summary>
/// <returns></returns>
public int active()
{
    int ret;

    ret = super();
    element.enableQueryButtons();

    return ret;
}

/// <summary>
///
/// </summary>
public void init()
{
    super();
    QueryBuildDataSource qbds = this.queryBuildDataSource();
    qbds.addDynalink(fieldNum(DBMSQLQueryStorePlanExt,queryId),DBMSQLQueryStoreExt,fieldNum(DBMSQLQueryStoreExt,queryId));
    QueryBuildDataSource qbdsRuntimeStats = qbds.addDataSource(tableNum(DBMSQLQueryStoreRuntimeStats));
    qbdsRuntimeStats.joinMode(JoinMode::ExistsJoin);
    qbdsRuntimeStats.fetchMode(QueryFetchMode::One2One);
    qbdsRuntimeStats.addLink(fieldNum(DBMSQLQueryStorePlanExt, planId), fieldNum(DBMSQLQueryStoreRuntimeStats, planId));
    QueryBuildDataSource qbdsRuntimeStatsInterval = qbdsRuntimeStats.addDataSource(tableNum(DBMSQLQueryStoreRuntimeStatsInterval));
    qbdsRuntimeStatsInterval.joinMode(JoinMode::InnerJoin);
    qbdsRuntimeStatsInterval.fetchMode(QueryFetchMode::One2One);
    qbdsRuntimeStatsInterval.addLink(fieldNum(DBMSQLQueryStoreRuntimeStats, RuntimeStatsIntervalId), fieldNum(DBMSQLQueryStoreRuntimeStatsInterval, RuntimeStatsIntervalId));
    qbrPlanStart =  qbdsRuntimeStatsInterval.addRange(fieldNum(DBMSQLQueryStoreRuntimeStatsInterval, startTime));
    qbrPlanEnd =  qbdsRuntimeStatsInterval.addRange(fieldNum(DBMSQLQueryStoreRuntimeStatsInterval, endTime));
}

/// <summary>
///
/// </summary>
public void executeQuery()
{
    super();
    Query query  = this.query();
    if (filterFrom.dateTimeValue() || filterTo.dateTimeValue())
    {
        utcdatetime fromDateTime = filterFrom.dateTimeValue();
        utcdatetime toDateTime = filterTo.dateTimeValue();
        query.dataSourceTable(tableNum(DBMSQLQueryStoreRuntimeStats)).enabled(true);
        query.dataSourceTable(tableNum(DBMSQLQueryStoreRuntimeStatsInterval)).enabled(true);
        switch(true)
        {
            case FromDateTime && toDateTime:
                qbrPlanStart.value(SysQuery::range(FromDateTime, ToDateTime));
                qbrPlanEnd.value(SysQuery::range(FromDateTime, ToDateTime));
                break;
            case FromDateTime && !ToDateTime:
                qbrPlanStart.value(SysQuery::range(FromDateTime, DateTimeUtil::maxValue()));
                qbrPlanEnd.value(SysQuery::range(FromDateTime, DateTimeUtil::maxValue()));
                break;
            case !FromDateTime && ToDateTime:
                qbrPlanStart.value(SysQuery::range(DateTimeUtil::minValue(), ToDateTime));
                qbrPlanEnd.value(SysQuery::range(DateTimeUtil::minValue(), ToDateTime));
                break;
        }
    }
    else
    {
        query.dataSourceTable(tableNum(DBMSQLQueryStoreRuntimeStats)).enabled(false);
        query.dataSourceTable(tableNum(DBMSQLQueryStoreRuntimeStatsInterval)).enabled(false);
    }

}

